import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationContext } from '../contexts/Notification.context';
import { notify } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (notificationElem) {
      notify(notificationElem, {
        heading: 'heading',
        subheading: 'subheading',
        type: 'warning',
      })
        .catch((err) => setError(err));
    }
  }, [notificationElem]);

  const triggerNotification = (props: NotificationProps) => {
    notify(notificationElem, props)
      .catch((err) => setError(err));
  };

  return { triggerNotification, error };
};

export default useNotification;
```

